const weekly = $('Fetch Weekly Downloads').first().json.downloads || 0;
const daily = $('Fetch Daily Downloads').first().json.downloads || 0;

const staticData = $getWorkflowStaticData('global');
const history = staticData.history || [];

const today = new Date().toISOString().split('T')[0];
history.push({ date: today, daily, weekly });

// Keep last 90 days
if (history.length > 90) history.shift();
staticData.history = history;

// Detect spike: daily > 3x average of last 7 days (require 7 days history)
const recent = history.slice(-8, -1);
const avgDaily = recent.length > 0 
  ? recent.reduce((sum, d) => sum + d.daily, 0) / recent.length 
  : 0;
const isSpike = recent.length >= 7 && avgDaily > 0 && daily > avgDaily * 3;
const isCrash = recent.length >= 7 && avgDaily > 5 && daily === 0;

return [{
  json: {
    date: today,
    daily,
    weekly,
    avgDaily: Math.round(avgDaily * 10) / 10,
    isSpike,
    isCrash,
    alert: isSpike || isCrash
  }
}];

